      purpose: "login",
      callStatus: method === "call" ? "pending" : undefined,
    });
    const clientName = dbUser.fullName || dbUser.username || "مستخدم";
    const { sendEmail, baseTemplate } = await import("./email");
    if (method === "whatsapp") {
      const waPhone = normPhone.replace("+", "").replace(/\s/g, "");
