        baseTemplate(`<p>العميل <strong>${clientName}</strong> يريد الدخول عبر رقم <strong dir="ltr">${normPhone}</strong></p>
        <p>رمز OTP: <strong style="font-size:24px;letter-spacing:6px;">${otp}</strong></p>
